class Solution:
    def splitListToParts(self, head, k):
        n = 0
        node = head
        while node:
            n += 1
            node = node.next
        base, extra = divmod(n, k)
        result = []
        cur = head
        for i in range(k):
            sz = base + (1 if i < extra else 0)
            result.append(cur if sz > 0 else None)
            prev = None
            for _ in range(sz):
                prev = cur
                cur = cur.next
            if prev:
                prev.next = None
        return result

