var splitListToParts = function(head, k) {
    let n = 0;
    let node = head;
    while (node) { n++; node = node.next; }
    const base = Math.floor(n / k);
    const extra = n % k;
    const result = [];
    let cur = head;
    for (let i = 0; i < k; i++) {
        const sz = base + (i < extra ? 1 : 0);
        result.push(sz > 0 ? cur : null);
        let prev = null;
        for (let j = 0; j < sz; j++) {
            prev = cur;
            cur = cur.next;
        }
        if (prev) prev.next = null;
    }
    return result;
};
